class Solution {
    public void gameOfLife(int[][] board) {
        int m = board.length;
        int n = board[0].length;

        // Make a copy to read from (preserve original state)
        int[][] copy = new int[m][n];
        for (int i = 0; i < m; i++) {
            copy[i] = board[i].clone();
        }

        int[] dr = {-1, -1, -1, 0, 0, 1, 1, 1};
        int[] dc = {-1,  0,  1,-1, 1,-1, 0, 1};

        for (int r = 0; r < m; r++) {
            for (int c = 0; c < n; c++) {
                int liveNeighbors = 0;
                for (int d = 0; d < 8; d++) {
                    int nr = r + dr[d];
                    int nc = c + dc[d];
                    if (nr >= 0 && nr < m && nc >= 0 && nc < n && copy[nr][nc] == 1) {
                        liveNeighbors++;
                    }
                }

                if (copy[r][c] == 1) {
                    // Rules 1 and 3: live cell dies from under/overpopulation
                    // Rule 2: live cell with 2 or 3 neighbors survives
                    board[r][c] = (liveNeighbors == 2 || liveNeighbors == 3) ? 1 : 0;
                } else {
                    // Rule 4: dead cell with exactly 3 neighbors becomes alive
                    board[r][c] = (liveNeighbors == 3) ? 1 : 0;
                }
            }
        }
    }
}

