class Solution {
    public void gameOfLife(int[][] board) {
        int m = board.length;
        int n = board[0].length;

        // Encoding:
        //  1  -> still alive (1 -> 1)
        // -1  -> was alive, will die (1 -> 0)
        //  2  -> was dead, will become alive (0 -> 1)
        //  0  -> still dead (0 -> 0)

        int[] dr = {-1, -1, -1, 0, 0, 1, 1, 1};
        int[] dc = {-1,  0,  1,-1, 1,-1, 0, 1};

        for (int r = 0; r < m; r++) {
            for (int c = 0; c < n; c++) {
                int liveNeighbors = 0;
                for (int d = 0; d < 8; d++) {
                    int nr = r + dr[d];
                    int nc = c + dc[d];
                    // Count cells that are currently alive (1 or -1)
                    if (nr >= 0 && nr < m && nc >= 0 && nc < n
                            && Math.abs(board[nr][nc]) == 1) {
                        liveNeighbors++;
                    }
                }

                if (board[r][c] == 1) {
                    if (liveNeighbors < 2 || liveNeighbors > 3) {
                        board[r][c] = -1; // alive -> dead
                    }
                    // else: stays 1 (alive -> alive)
                } else if (board[r][c] == 0) {
                    if (liveNeighbors == 3) {
                        board[r][c] = 2; // dead -> alive
                    }
                    // else: stays 0 (dead -> dead)
                }
            }
        }

        // Second pass: convert encoded values to final state
        for (int r = 0; r < m; r++) {
            for (int c = 0; c < n; c++) {
                if (board[r][c] == -1) board[r][c] = 0;
                if (board[r][c] ==  2) board[r][c] = 1;
            }
        }
    }
}

